class Solution {
    public String originalDigits(String s) {
        int[] count = new int[26];
        for (char c : s.toCharArray()) {
            count[c - 'a']++;
        }
        int[] digits = new int[10];
        digits[0] = count[24]; // z
        digits[2] = count[20]; // w
        digits[4] = count[5]; // u
        digits[6] = count[23]; // x
        digits[8] = count[7]; // g
        digits[1] = count[14] - digits[0] - digits[2] - digits[4]; // o
        digits[3] = count[8] - digits[0] - digits[2]; // h
        digits[5] = count[18] - digits[4]; // f
        digits[7] = count[6] - digits[0] - digits[2] - digits[4] - digits[6]; // s
        digits[9] = count[22] - digits[0] - digits[2] - digits[4] - digits[6] - digits[8]; // i
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 10; i++) {
            for (int j = 0; j < digits[i]; j++) {
                sb.append(i);
            }
        }
        return sb.toString();
    }
}
